import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Premium basics
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single plain sword yields premium of 115 G (100 base + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single plain amulet yields premium of 65 G");
  it.todo("single plain staff yields premium of 85 G");
  it.todo("single plain potion yields premium of 45 G");

  // Multiple items
  it.todo("plain sword + plain amulet yields premium of 165 G (100+60+5)");

  // Components
  it.todo("2 runes yield premium of 55 G (50 base + 5 fee)");
  it.todo("3 runes yield premium of 65 G (60 base block + 5 fee)");
  it.todo("4 runes yield premium of 105 G (4×25 + 5)");
  it.todo("7 runes yield premium of 180 G (175 + 5)");
  it.todo("2 runes + 1 moonstone yield premium of 80 G (no block, different types)");
  it.todo("3 runes + 3 moonstones yield premium of 125 G (two separate blocks)");

  // Modifiers
  it.todo("cursed sword adds 50% surcharge of its base premium");
  it.todo("highly enchanted sword (level ≥ 5) adds 30% surcharge");
  it.todo("loyalty discount of 20% applies for ≥ 2 years customer");
  it.todo("first insurance surcharge of 10% applies to each item");
  it.todo("follow-up contract gives 15% discount on subsequent contracts");

  // Modifier scope examples from spec
  it.todo("cursed sword + plain amulet: curse surcharge applies only to cursed item base");

  // Rounding
  it.todo("premium calculations round up (MHPCO's favor)");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
  it.todo("long-standing customer's 2nd contract with cursed sword (enchantment 7) → 160 G");

  // Claims — basic
  it.todo("standard claim: regular sword, damage 500 → payout 400 (minus 100 deductible)");
  it.todo("standard claim on rune: insurance value 250, damage 200 → payout 100");
  it.todo("high enchantment ≥ 8: 50% reimbursement then deductible");
  it.todo("dragon material: full reimbursement minus deductible");
  it.todo("dragon material + enchantment 9: 50% rule wins, then deductible");
  it.todo("dragon-material enchantment 5: only dragon clause, full reimbursement minus deductible");
  it.todo("deductible applies per damaged item (multi-damage event)");
  it.todo("payout calculation rounds down (MHPCO's favor)");

  // Multiple items of same type
  it.todo("two swords in policy, both damaged → each its own deductible");
  it.todo("damages contains more items of type than insured → error");

  // Errors
  it.todo("unknown item type in quote → throws / non-zero exit");
  it.todo("claim references item not in policy → throws / non-zero exit");
  it.todo("claim with negative damage amount → throws / non-zero exit");
});

