import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Premium basics
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single plain sword yields premium of 115 G (100 base + 10 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single plain amulet yields premium of 71 G (60 + 6 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single plain staff yields premium of 93 G (80 + 8 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single plain potion yields premium of 49 G (40 + 4 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Multiple items
  it("plain sword + plain amulet yields premium of 181 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }, { type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 181 }] });
  });

  // Components
  it("2 runes yield premium of 60 G (50 base + 5 first ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes yield premium of 71 G (block: 60 base + 6 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes yield premium of 115 G (4×25 = 100 base + 10 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes yield premium of 198 G (175 base + 17.5 first-ins + 5 fee = 197.5 → 198)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array(7).fill({ type: "rune" }),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone yield premium of 88 G (no block, different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones yield premium of 137 G (two separate blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Modifiers
  it("cursed sword: 0 years customer → 165 G (100 + 50 + 10 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword enchantment 5 → 145 G (100 + 30 + 10 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("loyalty discount: 2 years customer, plain sword → 95 G (100 base - 20 loyalty + 10 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3 }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("integration: long-standing customer's 2nd contract with cursed sword (enchantment 7) → 160 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        { op: "quote", items: [] },
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 5 }, { premium: 160 }] });
  });

  // Modifier scope examples from spec
  it("cursed sword + plain amulet: curse only on sword → 231 G (160 + 50 + 16 + 5)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
            { type: "amulet" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // Rounding (covered by 7-runes test)
  // Integration: newcomer with cursed sword — covered by cursed-sword 0-years test above
  it.todo("long-standing customer's 2nd contract with cursed sword (enchantment 7) → 160 G");

  // Claims — basic
  it("standard claim: regular sword, damage 500 → payout 400", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3 }] },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 500 }] },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400 });
  });
  it("standard claim on rune: damage 200 → payout 100", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }] },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "drop", damages: [{ itemType: "rune", amount: 200 }] },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 100 });
  });
  it("high enchantment ≥ 8: damage 1000 → payout 400 (500 - 100)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 8 }] },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1000 }] },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400 });
  });
  it("dragon material (enchantment 5): damage 800 → payout 700 (full - 100)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "dragon", enchantment: 5 }] },
        {
          op: "claim",
          policy: 0,
          incident: { cause: "fire", damages: [{ itemType: "sword", amount: 800 }] },
        },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 700 });
  });
  it.todo("dragon material + enchantment 9: 50% rule wins, then deductible");
  it.todo("dragon-material enchantment 5: only dragon clause, full reimbursement minus deductible");
  it.todo("deductible applies per damaged item (multi-damage event)");
  it.todo("payout calculation rounds down (MHPCO's favor)");

  // Multiple items of same type
  it.todo("two swords in policy, both damaged → each its own deductible");
  it.todo("damages contains more items of type than insured → error");

  // Errors
  it.todo("unknown item type in quote → throws / non-zero exit");
  it.todo("claim references item not in policy → throws / non-zero exit");
  it.todo("claim with negative damage amount → throws / non-zero exit");
});

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };

type QuoteStep = { op: "quote"; items: Item[] };
type Damage = { itemType: string; amount: number };
type ClaimStep = {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Damage[] };
};
type Step = QuoteStep | ClaimStep;

type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
type QuoteResult = { premium: number };
type ClaimResult = { payout: number };
type Result = QuoteResult | ClaimResult;

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const DEDUCTIBLE_PER_DAMAGE = 100;
const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25,
};
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const sum = (numbers: number[]): number => numbers.reduce((a, b) => a + b, 0);

const baseForItem = (item: Item): number => BASE_PREMIUM[item.type];

const baseForComponentGroup = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM.rune;

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const list = groups.get(item.type) ?? [];
    list.push(item);
    groups.set(item.type, list);
  }
  return groups;
};

const totalBaseForItems = (items: Item[]): number => {
  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
  const componentItems = items.filter((i) => COMPONENT_TYPES.has(i.type));
  const mainBase = sum(mainItems.map(baseForItem));
  const componentGroups = groupByType(componentItems);
  const componentBase = sum(
    Array.from(componentGroups.values()).map((group) => baseForComponentGroup(group.length)),
  );
  return mainBase + componentBase;
};

const itemSurcharges = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  let surcharge = 0;
  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
  return surcharge;
};

const computePremium = (items: Item[], isLoyal: boolean, isFollowUp: boolean): number => {
  const baseTotal = totalBaseForItems(items);
  const surchargesTotal = sum(items.map(itemSurcharges));
  const firstInsuranceTotal = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount = isLoyal ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
  const followUpDiscount = isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
  const total = baseTotal + surchargesTotal + firstInsuranceTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
  return Math.ceil(total);
};

const payoutForDamage = (damage: Damage, item: Item): number => {
  let reimbursable = damage.amount;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
    reimbursable = reimbursable * HIGH_ENCHANTMENT_PAYOUT_RATE;
  }
  return reimbursable - DEDUCTIBLE_PER_DAMAGE;
};

const computePayout = (damages: Damage[], policyItems: Item[]): number => {
  const total = sum(
    damages.map((d) => {
      const item = policyItems.find((i) => i.type === d.itemType);
      return payoutForDamage(d, item ?? { type: d.itemType });
    }),
  );
  return Math.floor(total);
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const isLoyal = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
  let quoteCount = 0;
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      return { premium: computePremium(step.items, isLoyal, isFollowUp) };
    }
    const policyStep = scenario.steps[step.policy];
    const policyItems = policyStep.op === "quote" ? policyStep.items : [];
    return { payout: computePayout(step.incident.damages, policyItems) };
  });
  return { results };
};

